import{_ as i,o as a,c as t,ae as e}from"./chunks/framework.D6sYw4vw.js";const l="/ai4energy.github.io/assets/image/91Tools/SSH_Git-10_12_40.png",p="/ai4energy.github.io/assets/image/91Tools/SSH_Git-10_14_22.png",u=JSON.parse('{"title":"SSH、Git与Git图形化软件","description":"","frontmatter":{},"headers":[],"relativePath":"docs/91Tools/3-ssh-git实操.md","filePath":"docs/91Tools/3-ssh-git实操.md","lastUpdated":1773485796000}'),n={name:"docs/91Tools/3-ssh-git实操.md"};function h(o,s,r,d,g,c){return a(),t("div",null,[...s[0]||(s[0]=[e(`<h1 id="ssh、git与git图形化软件" tabindex="-1">SSH、Git与Git图形化软件 <a class="header-anchor" href="#ssh、git与git图形化软件" aria-label="Permalink to &quot;SSH、Git与Git图形化软件&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">TIP</p><pre><code>Contents：SSH、Git与Git的图形化软件

Contributor: YJY

Email:522432938@qq.com

如有错误，请批评指正。
</code></pre><p>本文介绍ssh、git与git的图形化软件。他们之间的关系为：</p><ul><li>git基于ssh通讯操作</li><li>git图形化软件是操作git的图形化软件</li></ul><h2 id="ssh使用" tabindex="-1">SSH使用 <a class="header-anchor" href="#ssh使用" aria-label="Permalink to &quot;SSH使用&quot;">​</a></h2><h3 id="ssh是什么" tabindex="-1">SSH是什么 <a class="header-anchor" href="#ssh是什么" aria-label="Permalink to &quot;SSH是什么&quot;">​</a></h3><p>SSH是一种网络协议，用于计算机之间的加密登录。一个用户从本地计算机，使用SSH协议登录另一台远程计算机，就可以认为，这种登录是安全的，即使被中途截获，密码也不会泄露。</p><h3 id="ssh密钥登录原理" tabindex="-1">SSH密钥登录原理 <a class="header-anchor" href="#ssh密钥登录原理" aria-label="Permalink to &quot;SSH密钥登录原理&quot;">​</a></h3><ol><li>客户端发出认证请求；</li><li>服务器端使用客户端发送的公钥对一个随机的256位的字符串进行加密，并发送给 客户端；</li><li>客户端使用私钥对字符串进行解密，并生成一个MD5值发送给服务器端；</li><li>服务器端根据原始随机字符串生成MD5值进行匹配, 确认客户端身份；</li><li>至此, 双方互相确认对方身份并建立加密信道, 可以正式进行安全通信。</li></ol><h3 id="ssh的两种认证方式" tabindex="-1">SSH的两种认证方式 <a class="header-anchor" href="#ssh的两种认证方式" aria-label="Permalink to &quot;SSH的两种认证方式&quot;">​</a></h3><ul><li><strong>1.基于口令的安全认证</strong> ：提供正确的用户口令后可以登录远程服务器。</li></ul><p><strong>操作方式</strong>：</p><p>(默认端口为22)</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ssh user@host</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">example：</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ssh root@127.0.0.1</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ssh yjy@152.20.45.154</span></span></code></pre></div><p>然后输入登录密码进行登录 使用p参数，可以修改端口</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ssh </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">p 端口号 user@host</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">example：</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ssh </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">p </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">8080</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> yjy@152.20.45.154</span></span></code></pre></div><p>上面这个例子是以8080端口登录</p><ul><li><strong>2.基于密钥的安全认证</strong> ：使用公钥和私钥对的方式对用户进行认证。</li></ul><p>密钥登录首先需要产生<strong>公钥</strong>和<strong>私钥</strong>。</p><p>公钥放在服务端，私钥放在需要远程登录服务端的客户端</p><h5 id="产生公钥和私钥" tabindex="-1">产生公钥和私钥 <a class="header-anchor" href="#产生公钥和私钥" aria-label="Permalink to &quot;产生公钥和私钥&quot;">​</a></h5><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ssh</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">keygen </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">t rsa</span></span></code></pre></div><p>在~/.ssh文件夹（~为用户目录，windows和linux目录下都会有）下会出现id_rsa与id_rsa.pub两个文件。</p><p><strong>id_rsa是私钥，id_rsa.pub是公钥。</strong></p><h3 id="修改配置文件" tabindex="-1">修改配置文件 <a class="header-anchor" href="#修改配置文件" aria-label="Permalink to &quot;修改配置文件&quot;">​</a></h3><p>之后，在远程主机的ssh配置文件(/etc/ssh/sshd_config)中做如下修改，开启权限。这几项有些是新加上的，有些原来是no：</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">RSAAuthentication yes</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">PubkeyAuthentication yes</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">AuthorizedKeysFile .ssh</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">authorized_keys</span></span></code></pre></div><h3 id="在服务端存放公钥" tabindex="-1">在服务端存放公钥 <a class="header-anchor" href="#在服务端存放公钥" aria-label="Permalink to &quot;在服务端存放公钥&quot;">​</a></h3><p><strong>方法一：</strong></p><p>将公钥中的一大串字符添加到服务端~/.ssh/authorized_keys文件中去，如果已经存在，那么在后面再添上一条。不建议覆盖，因为这样其它客户端远程登录的公钥就会被覆盖！</p><p><strong>方法二：</strong></p><p>也可以用一段代码自动加过去</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ssh root@111.20.45.124 </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;mkdir -p .ssh &amp;&amp; cat &gt;&gt; .ssh/authorized_keys&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ~</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.ssh</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">id_rsa.pub</span></span></code></pre></div><p>这条命令由多个语句组成，依次分解开来看：</p><ul><li>（1）&quot;$ ssh user@host&quot;，表示登录远程主机；</li><li>（2）双引号中的mkdir .ssh &amp;&amp; cat &gt;&gt; .ssh/authorized_keys，表示登录后在远程shell上执行的命令：</li><li>（3）&quot;$ mkdir -p .ssh&quot;的作用是，如果用户主目录中的.ssh目录不存在，就创建一个；</li><li>（4）&#39;cat &gt;&gt; .ssh/authorized_keys&#39; &lt; ~/.ssh/id_rsa.pub的作用是，将本地的公钥文件~/.ssh/id_rsa.pub，重定向追加到远程文件authorized_keys的末尾。</li></ul><p><strong>写入authorized_keys文件后，公钥登录的设置就完成了</strong>。</p><p>现在就可以远程免密登录了！</p><h3 id="可能出现的问题" tabindex="-1">可能出现的问题 <a class="header-anchor" href="#可能出现的问题" aria-label="Permalink to &quot;可能出现的问题&quot;">​</a></h3><p>基本都是文件权限的问题，比如报错too open。Linux和Windows都会出现这样的情况，相关的解决方案很多，可以直接查找。</p><h3 id="登录github或者码云" tabindex="-1">登录github或者码云 <a class="header-anchor" href="#登录github或者码云" aria-label="Permalink to &quot;登录github或者码云&quot;">​</a></h3><p>用ssh怎么操作呢？</p><p>做一个转换，github相当于就是服务端，只需要把公钥放在服务端就可以了。在github上更加方便，因为它都是图形化软件操作。进入设置软件，选择ssh就可以进行调试了（码云同理）。</p><p>配置好了之后，可以进行如下测试：</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ssh </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">T git@github.com</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">（ssh </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">T git@gitee.com）</span></span></code></pre></div><h2 id="git的使用" tabindex="-1">git的使用 <a class="header-anchor" href="#git的使用" aria-label="Permalink to &quot;git的使用&quot;">​</a></h2><h3 id="git和ssh的关联" tabindex="-1">git和ssh的关联 <a class="header-anchor" href="#git和ssh的关联" aria-label="Permalink to &quot;git和ssh的关联&quot;">​</a></h3><p>之前讲了那么多ssh的知识，有什么作用呢？ 会了ssh，git基本就会了一半了！</p><h3 id="git的关键要素" tabindex="-1">git的关键要素 <a class="header-anchor" href="#git的关键要素" aria-label="Permalink to &quot;git的关键要素&quot;">​</a></h3><ul><li>本地工作区（自己电脑的文件夹）</li><li>远程仓库（远端服务器上的文件夹）</li></ul><h3 id="git基本操作" tabindex="-1">git基本操作 <a class="header-anchor" href="#git基本操作" aria-label="Permalink to &quot;git基本操作&quot;">​</a></h3><ul><li>初始化本地仓库</li><li>从远端拉取</li><li>在本地编写文件</li><li>文件暂存</li><li>提交修改</li><li>提交到远程</li></ul><p><strong>1.初始化本地仓库</strong></p><p>通过git bash或者cmd进入<strong>仓库文件夹</strong> 输入：</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">git init</span></span></code></pre></div><p>简单配置(相关教程也很多，不赘述)：</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">git config user.name </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Your Name&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">git config user.email </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;email@example.com&quot;</span></span></code></pre></div><p>链接到仓库的地址，相当于后面的操作就不需要输入地址了： （origin相当于变量，储存远端的地址）</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">git remote add origin </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;仓库的ssh地址&quot;</span></span></code></pre></div><p><strong>2.从远端拉取</strong></p><p>拉取origin的master分支</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>git pull origin master</span></span></code></pre></div><p><strong>3.本地编写文件</strong> 编写hello.txt</p><p><strong>4.提交暂存</strong></p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">git add .</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">##或者</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">git add hello.txt</span></span></code></pre></div><p><strong>5.提交修改</strong></p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">git commit </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">m </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;文件说明&quot;</span></span></code></pre></div><p><strong>6.推送到远端</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>git push origin master</span></span></code></pre></div><h3 id="git进阶操作" tabindex="-1">git进阶操作 <a class="header-anchor" href="#git进阶操作" aria-label="Permalink to &quot;git进阶操作&quot;">​</a></h3><ul><li>提交多个版本的文件</li><li>回退</li></ul><p><strong>1. 提交多个版本的文件</strong> hello.txt 版本1：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>i love you</span></span></code></pre></div><p>提交暂存并修改</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">git add hello.txt</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">git commit </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">m </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;first&quot;</span></span></code></pre></div><hr><p>hello.txt 版本2：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>i love you</span></span>
<span class="line"><span>I love you</span></span></code></pre></div><p>提交暂存并修改</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">git add hello.txt</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">git commit </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">m </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;second&quot;</span></span></code></pre></div><hr><p>hello.txt 版本3：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>i love you</span></span>
<span class="line"><span>I love you</span></span>
<span class="line"><span>I love you too much</span></span></code></pre></div><p>提交暂存并修改</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">git add hello.txt</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">git commit </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">m </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;third&quot;</span></span></code></pre></div><hr><p>接下来查看日志：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>git log</span></span></code></pre></div><p>如图： <img src="https://img-blog.csdnimg.cn/60aa7faa0d0f4d5286032357e95a3177.png?x-oss-process=image/watermark,type_ZHJvaWRzYW5zZmFsbGJhY2s,shadow_50,text_Q1NETiBAamFrZTQ4NA==,size_20,color_FFFFFF,t_70,g_se,x_16##pic_center" alt="在这里插入图片描述"></p><p>可以看到，HEAD 指向的是最新版本（head可以理解为当前版本，也就说如果要推到远程就是推这个版本）</p><p><strong>2.回退</strong> 接下来回退到上一个版本：</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">git reset </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">hard HEAD^ </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">##回退到上上个就是：HEAD^^</span></span></code></pre></div><p><img src="https://img-blog.csdnimg.cn/60bf07a3a1934f9698e188ee98073f86.png##pic_center" alt="在这里插入图片描述"></p><p>那么可以看到head确实变了</p><p>又不想回退了，还是要回到第三次改变的最新版本</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">git reset </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">hard 3ed54(commid的id，只能这样操作)</span></span></code></pre></div><p><strong>其实回退了之后就看不到id了，如果想要回到最新版本，就要记下id，所以说善变是有代价的！</strong></p><p>可以方便查看id与修改信息：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>git log --pretty=oneline</span></span></code></pre></div><p><strong>3.Push</strong> 在善变之后，找到了真爱，不管是谁吧，反正证还是要领的。最后就是把文件推送到远端了。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>git push origin master</span></span></code></pre></div><h2 id="git图形化软件" tabindex="-1">git图形化软件 <a class="header-anchor" href="#git图形化软件" aria-label="Permalink to &quot;git图形化软件&quot;">​</a></h2><p>git图形化软件的好处就是，把以上对git的操作图形化。</p><p>常用且免费的有：</p><ul><li>sourcetree</li><li>vscode中内嵌的git操作页面</li><li>gitkraken（团队版付费，个人免费）</li></ul><h3 id="sourcetree示例" tabindex="-1">sourcetree示例 <a class="header-anchor" href="#sourcetree示例" aria-label="Permalink to &quot;sourcetree示例&quot;">​</a></h3><p>软件如下：</p><p><img src="https://img-blog.csdnimg.cn/a165092494a149ff86abe8492d080b32.png?x-oss-process=image/watermark,type_ZHJvaWRzYW5zZmFsbGJhY2s,shadow_50,text_Q1NETiBAamFrZTQ4NA==,size_20,color_FFFFFF,t_70,g_se,x_16##pic_center" alt="在这里插入图片描述"></p><p>比如说clone：</p><p><img src="https://img-blog.csdnimg.cn/bfcd58f6f5ac4acaab4efd0e73f61bb0.png?x-oss-process=image/watermark,type_ZHJvaWRzYW5zZmFsbGJhY2s,shadow_50,text_Q1NETiBAamFrZTQ4NA==,size_20,color_FFFFFF,t_70,g_se,x_16##pic_center" alt="在这里插入图片描述"></p><p>某一个链接仓库的工作软件：</p><p><img src="https://img-blog.csdnimg.cn/f3cb4c32f83b47d8910c03c974b8f806.png?x-oss-process=image/watermark,type_ZHJvaWRzYW5zZmFsbGJhY2s,shadow_50,text_Q1NETiBAamFrZTQ4NA==,size_20,color_FFFFFF,t_70,g_se,x_16##pic_center" alt="在这里插入图片描述"></p><h3 id="vscode示例" tabindex="-1">vscode示例 <a class="header-anchor" href="#vscode示例" aria-label="Permalink to &quot;vscode示例&quot;">​</a></h3><p><img src="`+l+'" alt="图 4"></p><p>更多操作见<a href="./../Tools/vscode_git.html">vscode中使用git</a></p><h3 id="gitkraken示例" tabindex="-1">gitkraken示例 <a class="header-anchor" href="#gitkraken示例" aria-label="Permalink to &quot;gitkraken示例&quot;">​</a></h3><p><a href="https://www.gitkraken.com/" target="_blank" rel="noreferrer">gitkraken网址</a></p><p><img src="'+p+'" alt="图 5"></p><p>不管什么软件，拉取、提交、暂存等等都是相同的！</p><p><strong>如果你明白git的操作原理了，那么这个无师自通，因为本质上sourcetree就是提供一个图形化的操作软件。再没有其它新鲜玩意了！</strong></p></div>',2)])])}const E=i(n,[["render",h]]);export{u as __pageData,E as default};
